window.__QUIZ_DATA__=[{"id":"theory>Physics>2012>1","subject":"Physics","year":"2012","type":"Theory","sub_label":"1","group":"","topic":"EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES","question":"In the diagram illustrated beside, a body of mass m slides on an inclined plane. Show that the coefficient of friction between the surfaces in contact is tan \u03b8.","images":["data:image/png;base64,"],"marking_scheme":"Assume the normal reaction of mass m to be R, and the limiting friction to be F and the weight of mass to be Mg as we have in the diagram but let Mg = W, therefore, resolving forces along the plane,   we have that at equilibrium,   F = Wsin\u03b8 ..... (i)    Resolving perpendicular to the plane, we have that R = Wcos\u03b8 ..... (ii)   dividing (i) by (ii)   we have,   FR=Wsin\u03b8Wcos\u03b8=tan\u03b8    By definition, F/R = \u03bc    the co-efficient of friction   \u2234 \u03bc = F/R = tan\u03b8","marks":"3","difficulty":"3"},{"id":"theory>Physics>2012>2","subject":"Physics","year":"2012","type":"Theory","sub_label":"2","group":"FINAL","topic":"HOOKE\u2019S LAW, YOUNG\u2019S MODULES AND WORK DONE IN SPRINGS AND STRING :","question":"A spiral spring with a metal extends by 10.5cm in air. When the metal is fully submerged in water, the spring extends by 6.8cm. Calculate the relative density of the metal. (Assume Hooke's Law is obeyed)","images":[],"marking_scheme":"Parameters given:  Extension in air (e) = 10.5cm, extension in water (e1) = 6.8cm;  Relative density (Rs) = ?   Recall that: Rs = e/e -e1    Therefore;  Rs =  10.5/10.5 - 6.5 = 2.84","marks":"3","difficulty":"2"},{"id":"theory>Physics>2012>3","subject":"Physics","year":"2012","type":"Theory","sub_label":"3","group":"FINAL","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES","question":"A ray of light is incident on air-glass boundary at an angle \u03b8. If the angle between the partially reflected ray and the refracted ray is 90o, calculate \u03b8, given that the refractive index of glass is 1.50.","images":["data:image/png;base64,"],"marking_scheme":"According to Shell's law    n = sin\u03b8/sin r   where n = 1.5 but r + 90o + 0 = 180o ( sum of angles on a straight line)    r = 180 - (90 + \u03b8)    r = 90o - \u03b8   substitute 90o - \u03b8 for r in above    1.5 = sin\u03b8/sin(90 - \u03b8)   sin\u03b8 = 1.5sin(90 - \u03b8)  \u03b8 \u03b8 = 1.5(90 - \u03b8)   \u03b8 = tan-1 [1.5]   =56.31o","marks":"3","difficulty":"3"},{"id":"theory>Physics>2012>4>a","subject":"Physics","year":"2012","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELECTRIC FIELD : ELECTRIC CONDUCTION THROUGH MATERIALS","question":"Explain the term electrodes in electric cells.","images":[],"marking_scheme":"Electrodes are conductors through which electrons flow into or out of the electrolyte(of a cell)","marks":"1","difficulty":"1"},{"id":"theory>Physics>2012>4>b","subject":"Physics","year":"2012","type":"Theory","sub_label":"b","group":"FINAL","topic":"ELECTRIC FIELD : CURRENT ELECTRICITY","question":"An electric current passing through an electrolyte for 2 minutes deposited 200g of a substance. If the electrochemical equivalent of the substance is 8.33 x 10-4gC-1. Calculate the current passed.","images":[],"marking_scheme":"Parameters given:  time, t = 2mins = 2 x 60 = 120s (1mins=60seconds), Mass, m = 200g,Electrochemical constant, z = 8.33 x 10-4gC-4,   Therefore, M = zIt,    I = M/zt    = 200/8.33 x 10-4 x 120    = 200/0.09996    = 2000.8A","marks":"3","difficulty":"2"},{"id":"theory>Physics>2012>5","subject":"Physics","year":"2012","type":"Theory","sub_label":"5","group":"CLOSENESS","topic":"SOUND WAVES : CHARACTERISTICS OF SOUND","question":"Explain why sound waves cannot be plane polarized.","images":[],"marking_scheme":"Polarization is a characteristics of only transverse waves ,sound waves are longitudinal hence they cannot be plane polarized","marks":"3","difficulty":"2"},{"id":"theory>Physics>2012>6>a","subject":"Physics","year":"2012","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"FLUID AT REST : PRESSURE IN FLUIDS","question":"Define surface tension?","images":[],"marking_scheme":"It is a force per unit length acting in the surface at right angles to one sides of a line drawn in the surface of a liquid   -the property of a liquid that makes it behave as if its surfaces is an elastic skin","marks":"2","difficulty":"1"},{"id":"theory>Physics>2012>6>b","subject":"Physics","year":"2012","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"FLUID AT REST : PRESSURE IN FLUIDS","question":"State two methods by which the surface tension of a liquid  can be reduced.","images":[],"marking_scheme":"- The addition of detergent  - The addition of alcohol  - The addition of oil   - Increases the temperature","marks":"3","difficulty":"1"},{"id":"theory>Physics>2012>7","subject":"Physics","year":"2012","type":"Theory","sub_label":"7","group":"CLOSENESS","topic":"HEAT ENERGY : HEAT TRANSFER","question":"Explain why it is desirable to install an air conditioner near the ceiling of a room and not close to the floor.","images":[],"marking_scheme":"Air molecules near the ceiling get cooled ,become denser and cooled ,become denser and sink warming up molecules below being lighter rise  to the top ,get cooled become denser and get cooled again thus convectional current is set up","marks":"3","difficulty":"2"},{"id":"theory>Physics>2012>8>a","subject":"Physics","year":"2012","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"LIGHT WAVES : SOURCES OF LIGHT","question":"On what principle does lighting in a fluorescent tube operate?","images":[],"marking_scheme":"Electrical discharge through a gas at very low pressure and very high volume .","marks":"2","difficulty":"3"},{"id":"theory>Physics>2012>8>b","subject":"Physics","year":"2012","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"LIGHT WAVES : SOURCES OF LIGHT","question":"State two factors which determine the colour of light produced in a fluorescent tube.","images":[],"marking_scheme":"- Nature of the gas in the tube   - The nature of the powder coating inside the tube   - Voltage across the tube .","marks":"2","difficulty":"2"},{"id":"theory>Physics>2012>9","subject":"Physics","year":"2012","type":"Theory","sub_label":"9","group":"CLOSENESS","topic":"MAGNETIC FIELD : MAGNETIC FORCE ON A MOVING CHARGED PARTICLE","question":"The diagram beside illustrates an arrangement of a cathode ray from an electron gun and a bar magnet placed perpendicularly to the direction of the ray. Will the ray bend downward or upward? Explain.","images":["data:image/png;base64,"],"marking_scheme":"The direction of motion of the charge is due to the force acting on it which is mutually perpendicular to the direction of the magnetic field and the moving charge","marks":"1","difficulty":"3"},{"id":"theory>Physics>2012>10>a","subject":"Physics","year":"2012","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"WAVE-PARTICLE PARADOX : DUALITY OF MATTER","question":"Explain wave-particle duality of light.","images":[],"marking_scheme":"Lights exists in two forms wave and particle","marks":"1","difficulty":"3"},{"id":"theory>Physics>2012>10>b","subject":"Physics","year":"2012","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"WAVE-PARTICLE PARADOX : DUALITY OF MATTER","question":"Illustrate your answer in 10(a) with observable phenomena.","images":[],"marking_scheme":"wave nature -reflection,refraction ,diffraction,polarization,and interference   particle nature -emission and absorption of light  -photoelectric   -momentum  -radiation of energy from hot bodies","marks":"3","difficulty":"2"},{"id":"theory>Physics>2012>11>a","subject":"Physics","year":"2012","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"NEWTON\u2019S LAWS OF MOTION : THIRD LAW","question":"State the principle of conservation of linear momentum.","images":[],"marking_scheme":"Given that we have a closed system,that is composed of colliding objects, the total momentum is always conserved provided that there is no net external force acting on the system.","marks":"2","difficulty":"2"},{"id":"theory>Physics>2012>11>b","subject":"Physics","year":"2012","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"SATELLITES AND ROCKETS :","question":"Explain the mode of action of a propelled rocket.","images":[],"marking_scheme":"The principle of conservation of linear momentum is also applied in the propulsion of the rocket used for launching satellites. Gases are burnt within the combustion chambers of the engine. As jets of hot gases are expelled downwards through the tail nozzle at very high speeds from the rockets of aircrafts, an equal and opposite momentum is equal to the rocket which then moves the rocket.","marks":"3","difficulty":"3"},{"id":"theory>Physics>2012>11>c","subject":"Physics","year":"2012","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"SIMPLE HARMONIC MOTION : SIMPLE HARMONIC MOTION (S.H.M)","question":"During a training session, two footballers pass a ball repeatedly between themselves. Give two reasons why the to and fro motion of the ball is not simple harmonic","images":[],"marking_scheme":"- The acceleration of the ball is not directed towards a fixed point  - There is no equilibrium  - Acceleration of the ball is not directly proportional to displacement.","marks":"2","difficulty":"2"},{"id":"theory>Physics>2012>11>d>i","subject":"Physics","year":"2012","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"MOTION : MOTION UNDER GRAVITY","question":"A ball is dropped from a height, at the same time as another ball is projected horizontally from the same height.   Would the balls hit the ground at the same time?","images":[],"marking_scheme":"Yes/The balls would not hit the ground at the same time.","marks":"1","difficulty":"1"},{"id":"theory>Physics>2012>11>d>ii","subject":"Physics","year":"2012","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"MOTION : MOTION UNDER GRAVITY","question":"A ball is dropped from a height, at the same time as another ball is projected horizontally from the same height.    Explain your answer in (i)","images":[],"marking_scheme":"All objects are pulled towards the Earth by gravity and accelerate at a constant rate. This means that all free falling objects fall at the same rate.","marks":"2","difficulty":"2"},{"id":"theory>Physics>2012>11>e>i","subject":"Physics","year":"2012","type":"Theory","sub_label":"i","group":"FINAL","topic":"NEWTON\u2019S LAWS OF MOTION : SECOND LAW","question":"A ball of mass 0.100kg is projected horizontally onto a vertical wall with a speed of 17ms-1. The ball makes a contact with the wall for 0.15s and rebounds horizontally with a speed of 13ms-1. Calculate the change in momentum of the ball","images":[],"marking_scheme":"Given:   Mass of ball,m = 0.10kg, Initial velocity,    u1 = 17m/s, Time,    t = 0.15s,   Final velocity, v = 13m/s   Change in momentum = mv - (-mu1) = m(v + u) = 0.10(13 + 17) = 0.10(30)    = 3kgm/s","marks":"3","difficulty":"3"},{"id":"theory>Physics>2012>11>e>ii","subject":"Physics","year":"2012","type":"Theory","sub_label":"ii","group":"FINAL","topic":"NEWTON\u2019S LAWS OF MOTION : SECOND LAW","question":"A ball of mass 0.100kg is projected horizontally onto a vertical wall with a speed of 17ms-1. The ball makes a contact with the wall for 0.15s and rebounds horizontally with a speed of 13ms-1. Calculate the average force exerted on the ball during its collision with the wall.","images":[],"marking_scheme":"Average force, Fav = m(v + u)/t = 3/0.15   = 20N.","marks":"1","difficulty":"3"},{"id":"theory>Physics>2012>12>a>i","subject":"Physics","year":"2012","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"MACHINES :","question":"What is a machine?","images":[],"marking_scheme":"A machine is a device in which effort applied at one end is used to overcome a(greater) load/resistance at another point. It makes work easier.","marks":"2","difficulty":"1"},{"id":"theory>Physics>2012>12>a>ii","subject":"Physics","year":"2012","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"MACHINES :","question":"State two uses of gears.","images":[],"marking_scheme":"- To change direction   - It is used to move wheels by multiplying speed  - to magnify force","marks":"2","difficulty":"1"},{"id":"theory>Physics>2012>12>a>iii","subject":"Physics","year":"2012","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"MACHINES :","question":"Define the velocity ratio for a pair of gear wheels","images":[],"marking_scheme":"Mathematically,  Velocity ratio = number of teeth on driven wheel (A) to(/) number of teeth on driving wheel (B)","marks":"1","difficulty":"2"},{"id":"theory>Physics>2012>12>a>iv","subject":"Physics","year":"2012","type":"Theory","sub_label":"iv","group":"CLOSENESS","topic":"MACHINES :","question":"How can the mechanical advantage of a gear system be increased?","images":[],"marking_scheme":"To increase the mechanical advantage (M.A), the driving gear is made smaller and fewer teeth than the gear being driven","marks":"2","difficulty":"2"},{"id":"theory>Physics>2012>12>b>i","subject":"Physics","year":"2012","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"MACHINES :","question":"The diagram beside illustrates the gears system of a bicycle.   - Determine its velocity ratio","images":["data:image/png;base64,"],"marking_scheme":"From the diagram  Number of driving teeth = 18  Number of driven teeth = 12  V.R = 12/18  = 2/3","marks":"3","difficulty":"3"},{"id":"theory>Physics>2012>12>b>ii","subject":"Physics","year":"2012","type":"Theory","sub_label":"ii","group":"FINAL","topic":"MACHINES :","question":"The diagram beside illustrates the gears system of a bicycle.   If the bicycle has an efficiency of 90%, calculate the effort required to overcome a load of 70N.","images":["data:image/png;base64,"],"marking_scheme":"Efficiency E = M.A/V.R x 100    90/100 = 70/E /2/3  Effort =116.7N","marks":"3","difficulty":"3"},{"id":"theory>Physics>2012>12>b>iii","subject":"Physics","year":"2012","type":"Theory","sub_label":"iii","group":"","topic":"MACHINES :","question":"The diagram beside illustrates the gears system of a bicycle.   Why is the calculated effort less than the actual effort required?","images":["data:image/png;base64,"],"marking_scheme":"- Friction between the tyres and road  - Friction between chain and gear","marks":"1","difficulty":"2"},{"id":"theory>Physics>2012>13>a","subject":"Physics","year":"2012","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES","question":"Explain the term critical angle.","images":["data:image/png;base64,"],"marking_scheme":"Critical angle is the angle of incidence in the denser medium when the angle of refraction in the less dense medium is 90o.","marks":"2","difficulty":"1"},{"id":"theory>Physics>2012>13>b","subject":"Physics","year":"2012","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"LIGHT WAVES : DISPERSION OF WHITE LIGHT","question":"List two factors which determine the deviation of a ray of light by a triangular glass prism.","images":[],"marking_scheme":"- angle of incidence  - refracting angle of the prism  - refractive index of the material of the prism","marks":"2","difficulty":"1"},{"id":"theory>Physics>2012>13>c","subject":"Physics","year":"2012","type":"Theory","sub_label":"c","group":"FINAL","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES","question":"The angle of refraction(r) of a ray of white light from air through a triangular glass prism of refraction index 1.5 is 29.0o. Calculate the angle through which the ray is least deviated.","images":[],"marking_scheme":"n = [Sin1/2(A + Dm)] / [Sin 1/2(A)]  *:  A = 2r = 2\u00d729 = 58   Sin1/2(A + Dm) = n Sin1/2(A)  1/2 (A + Dm) = Sin -1 (1.5 \u00d7 Sin 1/2 \u00d7 58)= Sin -1 0.7272 = 46.67  58+ Dm = 93.32  Dm = 35.32o","marks":"4","difficulty":"3"},{"id":"theory>Physics>2012>13>d>i","subject":"Physics","year":"2012","type":"Theory","sub_label":"i","group":"FINAL","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES","question":"Study the ray diagram beside and use it to answer the questions that follow.    Calculate the:    (i) values of angles P, Q and R    (ii) refractive index of the glass prism  (iii) value of e;    (iv) total deviation D.","images":["data:image/png;base64,"],"marking_scheme":"P + 20 = 45o (vertically opposite \u2220s)   \u2234 P = 45 - 20 = 25o    2Q + 60 + 60 = 360o  (angles at a point)   Q = 360 - 120 = 240    Q = 240/2 = 120o    P + Q + R = 180o (sum of interior angles of a triangle)    25 + 120 + R = 18o   \u2234 R = 180 - (25 + 120)    R = 35o","marks":"2","difficulty":"3"},{"id":"theory>Physics>2012>13>d>ii","subject":"Physics","year":"2012","type":"Theory","sub_label":"ii","group":"FINAL","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES","question":"Study the ray diagram beside and use it to answer this question.    Calculate the refractive index of the glass prism","images":["data:image/png;base64,"],"marking_scheme":"According to Snell's law    Refractive index= sin of angle of incidence/sine of angle of refraction  Therefore,n = sin i/sin P    = sin45o/sin 25o = 0.7071/0.4226    = 1.67","marks":"2","difficulty":"2"},{"id":"theory>Physics>2012>13>d>iii","subject":"Physics","year":"2012","type":"Theory","sub_label":"iii","group":"FINAL","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES","question":"Study the ray diagram beside and use it to answer this question. Calculate the value of e.","images":["data:image/png;base64,"],"marking_scheme":"n = Sin e/ Sin R  1.673 =  Sin e/ Sin 35 o  Sin e = 1.673 \u00d7 Sin 35 ^ (o)=0.9595  e = Sin -1 (0.9595)   = 73.7o","marks":"1","difficulty":"2"},{"id":"theory>Physics>2012>13>d>iv","subject":"Physics","year":"2012","type":"Theory","sub_label":"iv","group":"FINAL","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES","question":"Study the ray diagram beside and use it to answer this question. Calculate the total deviation D.","images":["data:image/png;base64,"],"marking_scheme":"From the diagram given,   The total deviation, that is the angle between the incident ray and the emergent ray.   Total deviation     D = (i + e) - A = (45 + 73.3) - 60   = 58.3o","marks":"1","difficulty":"2"},{"id":"theory>Physics>2012>14>a","subject":"Physics","year":"2012","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"MAGNETIC FIELD : CONCEPT OF MAGNETIC FIELD","question":"Define magnetic line of force","images":[],"marking_scheme":"Magnetic line of force are imaginary lines through which a free-North pole would tend to move if placed on the field. A line of force on the other side, may be explained as a line in which the tangent to it at any point gives the direction of the field at the point","marks":"1","difficulty":"1"},{"id":"theory>Physics>2012>14>b>i","subject":"Physics","year":"2012","type":"Theory","sub_label":"i","group":"FINAL","topic":"MAGNETIC FIELD : CURRENT-CARRYING CONDUCTOR IN A MAGNETIC FIELD","question":"A wire of length 10cm carrying a current of 4.0A is placed between the poles of a powerful electromagnetic flux density 2.0T. Calculate the force on the wire when it is parallel to the field","images":[],"marking_scheme":"Recall that:F = BILsin\u03b8   Parameters given;flux density B = 2.0T  length = 10cm = 0.1m  Current A = 4.0A, when it is parallel \u03b8 = 0,    F = 2 x 0.1 x 4sin\u03b8 = 2 x 0.1 x 4 x 0     F = 0","marks":"1","difficulty":"3"},{"id":"theory>Physics>2012>14>b>ii","subject":"Physics","year":"2012","type":"Theory","sub_label":"ii","group":"FINAL","topic":"MAGNETIC FIELD : CURRENT-CARRYING CONDUCTOR IN A MAGNETIC FIELD","question":"A wire of length 10cm carrying a current of 4.0A is placed between the poles of a powerful electromagnetic flux density 2.0T. Calculate the maximum force on the wire","images":[],"marking_scheme":"From the parameters given,   F = BIL = 2 x 4 x 0.1 = 8 x 0.1 = 0.8N","marks":"1","difficulty":"3"},{"id":"theory>Physics>2012>14>b>iii","subject":"Physics","year":"2012","type":"Theory","sub_label":"iii","group":"FINAL","topic":"MAGNETIC FIELD : CURRENT-CARRYING CONDUCTOR IN A MAGNETIC FIELD","question":"A wire of length 10cm carrying a current of 4.0A is placed between the poles of a powerful electromagnetic flux density 2.0T. Calculate the force on the wire when it makes an angle 60o with the field.","images":[],"marking_scheme":"From the parameters given:  F = BILsin\u03b8 = 2 x 4 x 0.1sin60o = 0.8 x 0.8660 = 0.6928 = 0.69N","marks":"1","difficulty":"3"},{"id":"theory>Physics>2012>14>c","subject":"Physics","year":"2012","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"MAGNETIC FIELD : MAGNETIZATION AND DEMAGNETIZATION","question":"Describe how keepers can be used to preserve the magnetic strength of permanent bar magnets.","images":["data:image/png;base64,"],"marking_scheme":"- Store in pairs with their opposite poles adjacent  - Small pieces of soft iron called keepers are placed across their ends  - By induction the keepers become magnets decreasing the reluctance of the gaps  - Both magnets and keepers form closed loops","marks":"4","difficulty":"2"},{"id":"theory>Physics>2012>14>d","subject":"Physics","year":"2012","type":"Theory","sub_label":"d","group":"FINAL","topic":"MAGNETIC FIELD : THE EARTH\u2019S MAGNETIC FIELD","question":"A sailor observes that his mariners' compass reads N10oW at a pace where the angle of declination is N15oW. Calculate the true bearing of the place.","images":[],"marking_scheme":"From the parameters given:   Angle of true bearing = 10o + 15o    = N25o W","marks":"2","difficulty":"3"},{"id":"theory>Physics>2012>15>a>i","subject":"Physics","year":"2012","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : X-RAYS","question":"Explain why x-rays can be used to produce photographs of fractures in bones.","images":[],"marking_scheme":"X-rays cannot penetrate bones but can pass through fractures","marks":"2","difficulty":"2"},{"id":"theory>Physics>2012>15>a>ii","subject":"Physics","year":"2012","type":"Theory","sub_label":"ii","group":"","topic":"STRUCTURE OF THE ATOM : X-RAYS","question":"List four uses of x-rays other than in medicine","images":[],"marking_scheme":"- Examination of bags/luggage at airport / sensitive places  - Identification of chemical elements and their isotopes  - Detection of cracks in metall/products  - Detection of fake gems   - Detection of alteration which have been made to original works of art","marks":"2","difficulty":"1"},{"id":"theory>Physics>2012>15>b","subject":"Physics","year":"2012","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : X-RAYS","question":"State the energy transformations which takes place during the operation of an x-ray tube.","images":[],"marking_scheme":"The energy transformation processes which take place during the operation of an x-ray tube can be explained as thus:  The electrical energy is converted into the thermal energy. This thermal energy is converted into the mechanical kinetic energy of the accelerated energy of the x-rays and thermal energy.","marks":"2","difficulty":"2"},{"id":"theory>Physics>2012>15>c>i","subject":"Physics","year":"2012","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : X-RAYS","question":"Explain **three* named dangers to which human beings may be exposed when subjected to large doses of x-rays.","images":[],"marking_scheme":"- Cancer - destruction of living cells, tissues and organ  - Leukemia - destruction of white blood cells  - Skin harm - tanning/burning of skin  - Cell mutation - change in cell genetic codes","marks":"3","difficulty":"2"},{"id":"theory>Physics>2012>15>c>ii","subject":"Physics","year":"2012","type":"Theory","sub_label":"ii","group":"","topic":"STRUCTURE OF THE ATOM : X-RAYS","question":"State two precautions that must be taken by persons working with x-rays.","images":[],"marking_scheme":"- They should have routine medical check ups  - They should wear lead/prospective coats  - They should wear dosimeter  - They should wear protective goggles","marks":"2","difficulty":"1"},{"id":"theory>Physics>2012>15>d>i","subject":"Physics","year":"2012","type":"Theory","sub_label":"i","group":"","topic":"STRUCTURE OF THE ATOM : X-RAYS","question":"In an x-ray tube, an electron is accelerated from rest towards a tungsten target based at a potential of 33kV. Calculate, for the electron, the velocity   [h = 6.6 x 10-34Js; Me = 9.1 x 10-31Kg, c = 3.0 x 10-8ms-1, e = 1.6 x 10-19C]","images":[],"marking_scheme":"K.E = 1eV = 1.6 \u00d7 10-19 \u00d7 33 \u00d7 103 = 5.28 \u00d7 10-15J","marks":"2","difficulty":"3"},{"id":"theory>Physics>2012>15>d>ii","subject":"Physics","year":"2012","type":"Theory","sub_label":"ii","group":"","topic":"STRUCTURE OF THE ATOM : X-RAYS","question":"In an x-ray tube, an electron is accelerated from rest towards a tungsten target based at a potential of 33kV. Calculate, for the electron, the velocity   [h = 6.6 x 10-34Js; Me = 9.1 x 10-31Kg, c = 3.0 x 10-8ms-1, e = 1.6 x 10-19C]","images":[],"marking_scheme":"K.E = 1/2 mv2  5.28 \u00d7 10-15 = 1/2 \u00d7 9.1\u00d7 10-31 \u00d7 V2  V2 = 1.16 \u00d7 1016  V = 1.08  \u00d7 108 ms-1","marks":"2","difficulty":"3"}];